/**
 * State Storage
 *
 * Manages current task state via storage/state.json
 * Generates context/now.md for Claude
 *
 * Note: Local .prjct-state.md is generated by sync-service which has access
 * to projectPath. This class only has projectId.
 */

import type {
  CurrentTask,
  PreviousTask,
  StateJson,
  Subtask,
  SubtaskCompletionData,
  TaskFeedback,
  TaskHistoryEntry,
  WorkspaceTask,
} from '../schemas/state'
import { StateJsonSchema } from '../schemas/state'
import type { WorkflowCommand } from '../types/workflow'
import { getTimestamp } from '../utils/date-helper'
import { workflowStateMachine } from '../workflow-engine/state-machine'
import prjctDb from './database'
import type { LifecycleBackend } from './state-storage/lifecycle'
import * as lifecycle from './state-storage/lifecycle'
import type { QueryBackend } from './state-storage/queries'
import * as queries from './state-storage/queries'
import type { SubtaskBackend } from './state-storage/subtasks'
import * as subtasks from './state-storage/subtasks'
import type { WorkspaceBackend } from './state-storage/workspace'
import * as workspace from './state-storage/workspace'
import { StorageManager } from './storage-manager'

/**
 * The subset of task-shaped fields mirrorTaskRow needs, shared across
 * CurrentTask / PreviousTask / WorkspaceTask. PreviousTask has no
 * branch/linkedSpecId — the mirror's COALESCE-on-existing-row SQL already
 * treats a missing value as "don't touch," so making them optional here is safe.
 */
type MirrorableTask = {
  id: string
  description: string
  type?: CurrentTask['type']
  branch?: string
  linkedSpecId?: string
  sessionId?: string
  featureId?: string
  startedAt?: string
}

class StateStorage extends StorageManager<StateJson> {
  constructor() {
    super('state.json', StateJsonSchema)
  }

  protected getDefault(): StateJson {
    return {
      currentTask: null,
      previousTask: null,
      pausedTasks: [],
      taskHistory: [],
      activeTasks: [],
      lastUpdated: '',
    }
  }

  protected getEventType(action: 'update' | 'create' | 'delete'): string {
    return `state.${action}d`
  }

  // =========== Transition Validation ===========

  /**
   * Validate a state transition through the state machine.
   * Throws if the transition is invalid.
   *
   * When `workspaceId` is provided the lifecycle is evaluated PER workspace
   * (multi-agent parallel mode): a task active in one worktree does not block
   * starting one in another, but a second task in the SAME workspace still
   * gates. Omitting it preserves the legacy singular (currentTask) gate.
   */
  private validateTransition(
    state: StateJson,
    command: WorkflowCommand,
    workspaceId?: string
  ): void {
    const currentState = workflowStateMachine.getCurrentState(state, workspaceId)
    const result = workflowStateMachine.canTransition(currentState, command)
    if (!result.valid) {
      throw new Error(`${result.error}. ${result.suggestion || ''}`.trim())
    }
  }

  // =========== Domain Methods ===========

  /**
   * Get current active task
   */
  async getCurrentTask(projectId: string): Promise<CurrentTask | null> {
    const state = await this.read(projectId)
    return state.currentTask
  }

  /**
   * Loop control: bump the active cycle's turn counter by one and return the new
   * value (0 when there is no active cycle). Called once per turn from the
   * UserPromptSubmit hook so the state block can escalate a stuck loop. A new
   * cycle starts with no turnCount, so it resets naturally.
   */
  /**
   * Bump turn counter and return count + the post-bump task (avoids a second
   * read on the UserPromptSubmit hot path).
   */
  async bumpTurnCount(projectId: string): Promise<{ count: number; task: CurrentTask | null }> {
    const resultRef: { count: number; task: CurrentTask | null } = {
      count: 0,
      task: null,
    }
    await this.update(projectId, (state) => {
      if (!state.currentTask) return state
      const next = (state.currentTask.turnCount ?? 0) + 1
      const task = { ...state.currentTask, turnCount: next }
      resultRef.count = next
      resultRef.task = task
      return { ...state, currentTask: task }
    })
    return resultRef
  }

  /**
   * Hard loop guard consent: stamp the active cycle as acknowledged so the
   * maxTurnsPerCycle block stops firing for THIS cycle (`prjct work --extend`).
   * Returns false when there is no active cycle. A new cycle clears it naturally.
   */
  async acknowledgeTurnLimit(projectId: string, at: string): Promise<boolean> {
    const resultRef: { ok: boolean } = { ok: false }
    await this.update(projectId, (state) => {
      if (!state.currentTask) return state
      resultRef.ok = true
      return { ...state, currentTask: { ...state.currentTask, turnLimitAcknowledgedAt: at } }
    })
    return resultRef.ok
  }

  /**
   * Get paused tasks (most-recent first). Returns empty array if none.
   */
  async getPausedTasks(projectId: string): Promise<PreviousTask[]> {
    const state = await this.read(projectId)
    return this.getPausedTasksFromState(state)
  }

  /**
   * Start a new task
   */
  async startTask(projectId: string, task: Omit<CurrentTask, 'startedAt'>): Promise<CurrentTask> {
    const resultRef: { currentTask?: CurrentTask } = {}
    await this.update(projectId, (state) => {
      this.validateTransition(state, 'task')
      resultRef.currentTask = {
        ...task,
        startedAt: getTimestamp(),
      }
      return {
        ...state,
        currentTask: resultRef.currentTask,
        lastUpdated: getTimestamp(),
      }
    })

    if (!resultRef.currentTask) throw new Error('Failed to start task')
    const currentTask = resultRef.currentTask

    // Schema v2 (C4): mirror the live cycle into the typed `tasks` table so it's
    // queryable (cost coverage, dashboard, cloud) without parsing the kv_store
    // state doc. The kv_store state remains the live source for the work loop;
    // this is the dual-write phase. Best-effort.
    this.mirrorTaskRow(projectId, currentTask, 'in_progress')

    // Publish incremental event
    await this.publishEvent(projectId, 'task.started', {
      taskId: currentTask.id,
      description: currentTask.description,
      startedAt: currentTask.startedAt,
      sessionId: currentTask.sessionId,
    })

    return currentTask
  }

  /**
   * Schema v2 (C4) dual-write: upsert a work cycle into the typed `tasks`
   * table. Additive mirror — never the live read path for the work loop, never
   * throws. One DB per project, so no project_id column on `tasks`.
   *
   * Called from every lifecycle transition that changes a cycle's status
   * (start/pause/resume/complete, singular AND per-workspace/multi-agent), not
   * just start/complete — a task left un-mirrored on pause previously stayed
   * `status='in_progress'` in the typed table forever, and workspace-parallel
   * cycles never appeared in `tasks` at all (invisible to cost/dashboard/cloud
   * consumers of the typed table).
   */
  private mirrorTaskRow(
    projectId: string,
    task: MirrorableTask,
    status: string,
    extra: { completedAt?: string; pausedAt?: string; pauseReason?: string } = {}
  ): void {
    try {
      prjctDb.run(
        projectId,
        `INSERT INTO tasks (id, description, type, status, branch, linked_spec_id, session_id, feature_id, started_at, completed_at, paused_at, pause_reason)
         VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
         ON CONFLICT(id) DO UPDATE SET
           description = excluded.description,
           status = excluded.status,
           branch = COALESCE(excluded.branch, tasks.branch),
           linked_spec_id = COALESCE(excluded.linked_spec_id, tasks.linked_spec_id),
           completed_at = COALESCE(excluded.completed_at, tasks.completed_at),
           paused_at = excluded.paused_at,
           pause_reason = excluded.pause_reason`,
        task.id,
        task.description,
        task.type ?? null,
        status,
        task.branch ?? null,
        task.linkedSpecId ?? null,
        task.sessionId ?? null,
        task.featureId ?? null,
        task.startedAt ?? null,
        extra.completedAt ?? null,
        extra.pausedAt ?? null,
        extra.pauseReason ?? null
      )
    } catch {
      /* best-effort mirror — kv_store state is the live source of truth */
    }
  }

  /**
   * Schema v2 (C4): persist a completed task's FULL history entry into the
   * typed `tasks` row — hot fields as columns, the history-only extras
   * (outcome, subtask summaries, feedback, harness) on the cold `data`
   * column. History queries (`getTaskHistory` et al.) read this, not the
   * state blob. Upsert by task id so ordering vs `mirrorTaskRow` never
   * matters. Best-effort: history must never block a completion. Token
   * columns are keep-if-zero: the history entry carries tokens only from the
   * kv task's addTokens trail, while the Stop hook writes transcript totals
   * straight onto the row — a 0 here must not clobber a measured total.
   */
  private mirrorHistoryEntry(projectId: string, entry: TaskHistoryEntry): void {
    try {
      const cold = JSON.stringify({
        title: entry.title,
        outcome: entry.outcome,
        subtaskCount: entry.subtaskCount,
        subtaskSummaries: entry.subtaskSummaries,
        feedback: entry.feedback,
        harness: entry.harness,
        linearUuid: entry.linearUuid,
      })
      prjctDb.run(
        projectId,
        `INSERT INTO tasks (id, description, type, status, branch, linear_id, pr_url, started_at, completed_at, tokens_in, tokens_out, data)
         VALUES (?, ?, ?, 'completed', ?, ?, ?, ?, ?, ?, ?, ?)
         ON CONFLICT(id) DO UPDATE SET
           description = excluded.description,
           type = excluded.type,
           status = 'completed',
           branch = COALESCE(excluded.branch, tasks.branch),
           linear_id = COALESCE(excluded.linear_id, tasks.linear_id),
           started_at = COALESCE(excluded.started_at, tasks.started_at),
           completed_at = excluded.completed_at,
           pr_url = COALESCE(excluded.pr_url, tasks.pr_url),
           tokens_in = CASE WHEN excluded.tokens_in > 0 THEN excluded.tokens_in ELSE tasks.tokens_in END,
           tokens_out = CASE WHEN excluded.tokens_out > 0 THEN excluded.tokens_out ELSE tasks.tokens_out END,
           data = excluded.data`,
        entry.taskId,
        entry.title,
        entry.classification,
        entry.branchName === 'unknown' ? null : entry.branchName,
        entry.linearId ?? null,
        entry.prUrl ?? null,
        entry.startedAt,
        entry.completedAt,
        entry.tokensIn ?? 0,
        entry.tokensOut ?? 0,
        cold
      )
    } catch {
      /* best-effort history mirror */
    }
  }

  /**
   * Update fields on the current task (partial update).
   * Keys set to `null` are deleted (used to clear optional markers like
   * `pendingHandoffId` after accept).
   */
  async updateCurrentTask(
    projectId: string,
    fields: Partial<CurrentTask> & Record<string, unknown>
  ): Promise<CurrentTask | null> {
    let updated: CurrentTask | null = null
    await this.update(projectId, (s) => {
      if (!s.currentTask) return s
      const next: Record<string, unknown> = { ...s.currentTask }
      for (const [k, v] of Object.entries(fields)) {
        if (v === null) delete next[k]
        else if (v !== undefined) next[k] = v
      }
      updated = next as CurrentTask
      return {
        ...s,
        currentTask: updated,
        lastUpdated: getTimestamp(),
      }
    })

    return updated
  }

  /**
   * Complete current task
   * Persists the TaskHistoryEntry into the typed `tasks` table (Schema v2 C4 —
   * history reads come from there; the state blob no longer carries history).
   * Optionally accepts structured feedback for the task-to-analysis feedback loop (PRJ-272)
   */
  async completeTask(projectId: string, feedback?: TaskFeedback): Promise<CurrentTask | null> {
    const completedAt = getTimestamp()
    const resultRef: { completedTask?: CurrentTask } = {}
    await this.update(projectId, (state) => {
      if (!state.currentTask) return state
      this.validateTransition(state, 'done')
      resultRef.completedTask = state.currentTask
      return {
        ...state,
        currentTask: null,
        previousTask: null,
        lastUpdated: completedAt,
      }
    })

    if (!resultRef.completedTask) return null
    const completedTask = resultRef.completedTask

    // Schema v2 (C4): mark the typed mirror completed, then persist the full
    // history entry (classification/outcome/feedback/harness/tokens) so
    // history queries read the typed table instead of a blob list.
    this.mirrorTaskRow(projectId, completedTask, 'completed', { completedAt })
    this.mirrorHistoryEntry(
      projectId,
      this.createTaskHistoryEntry(completedTask, completedAt, feedback)
    )

    // Publish incremental event
    await this.publishEvent(projectId, 'task.completed', {
      taskId: completedTask.id,
      description: completedTask.description,
      startedAt: completedTask.startedAt,
      completedAt,
    })

    return completedTask
  }

  /**
   * Create a TaskHistoryEntry from a completed task
   * Optionally includes structured feedback for the feedback loop (PRJ-272)
   */
  private createTaskHistoryEntry(
    task: CurrentTask,
    completedAt: string,
    feedback?: TaskFeedback
  ): TaskHistoryEntry {
    // Extract subtask summaries (only completed subtasks with summaries)
    const subtaskSummaries = (task.subtasks || [])
      .filter((st) => st.status === 'completed' && st.summary)
      .map((st) => st.summary!)

    // Calculate outcome description from subtask summaries
    const outcome =
      subtaskSummaries.length > 0
        ? subtaskSummaries.map((s) => s.title).join(', ')
        : 'Task completed'

    const entry: TaskHistoryEntry = {
      taskId: task.id,
      title: task.parentDescription || task.description,
      classification: task.type || 'improvement',
      startedAt: task.startedAt,
      completedAt,
      subtaskCount: task.subtasks?.length || 0,
      subtaskSummaries,
      outcome,
      branchName: task.branch || 'unknown',
      linearId: task.linearId,
      linearUuid: task.linearUuid,
      prUrl: task.prUrl,
      harness: task.harness,
    }

    // Attach feedback if provided (PRJ-272)
    if (feedback) {
      entry.feedback = feedback
    }

    // Carry token usage totals
    if (task.tokensIn) entry.tokensIn = task.tokensIn
    if (task.tokensOut) entry.tokensOut = task.tokensOut

    return entry
  }

  /** Max number of paused tasks (configurable) */
  private maxPausedTasks = 5

  /** Staleness threshold in days */
  private stalenessThresholdDays = 30

  // =========== Pause/Resume/Archive (delegated to ./state-storage/lifecycle) ===========

  private lifecycleBackend(): LifecycleBackend {
    return {
      read: this.read.bind(this),
      update: this.update.bind(this),
      publish: this.publishEvent.bind(this),
      validateTransition: this.validateTransition.bind(this),
      getPausedTasksFromState: this.getPausedTasksFromState.bind(this),
      maxPausedTasks: this.maxPausedTasks,
      stalenessThresholdDays: this.stalenessThresholdDays,
    }
  }

  async pauseTask(projectId: string, reason?: string): Promise<PreviousTask | null> {
    const paused = await lifecycle.pauseTask(this.lifecycleBackend(), projectId, reason)
    // Schema v2 (C4) dual-write: without this, a paused task stayed
    // status='in_progress' in the typed `tasks` table indefinitely — any
    // cost/dashboard/cloud consumer of that table saw phantom active work.
    if (paused) {
      this.mirrorTaskRow(projectId, paused, 'paused', {
        pausedAt: paused.pausedAt,
        pauseReason: paused.pauseReason,
      })
    }
    return paused
  }

  async resumeTask(projectId: string, taskId?: string): Promise<CurrentTask | null> {
    const resumed = await lifecycle.resumeTask(this.lifecycleBackend(), projectId, taskId)
    if (resumed) {
      this.mirrorTaskRow(projectId, resumed, 'in_progress')
    }
    return resumed
  }

  /**
   * Get paused tasks from state
   */
  private getPausedTasksFromState(state: StateJson): PreviousTask[] {
    if (Array.isArray(state.pausedTasks) && state.pausedTasks.length > 0) {
      return state.pausedTasks
    }
    // Migrate legacy previousTask into pausedTasks (PRJ-345)
    if (state.previousTask) {
      return [state.previousTask]
    }
    return []
  }

  async getStalePausedTasks(projectId: string): Promise<PreviousTask[]> {
    return lifecycle.getStalePausedTasks(this.lifecycleBackend(), projectId)
  }

  async archiveStalePausedTasks(projectId: string): Promise<PreviousTask[]> {
    return lifecycle.archiveStalePausedTasks(this.lifecycleBackend(), projectId)
  }

  // =========== Query helpers (delegated to ./state-storage/queries) ===========

  private queryBackend(): QueryBackend {
    return {
      read: this.read.bind(this),
      update: this.update.bind(this),
      getPausedTasksFromState: this.getPausedTasksFromState.bind(this),
    }
  }

  async clearTask(projectId: string): Promise<void> {
    return queries.clearTask(this.queryBackend(), projectId)
  }

  async hasTask(projectId: string): Promise<boolean> {
    return queries.hasTask(this.queryBackend(), projectId)
  }

  async getPausedTask(projectId: string): Promise<PreviousTask | null> {
    return queries.getPausedTask(this.queryBackend(), projectId)
  }

  async getAllPausedTasks(projectId: string): Promise<PreviousTask[]> {
    return queries.getAllPausedTasks(this.queryBackend(), projectId)
  }

  async getTaskHistory(projectId: string): Promise<TaskHistoryEntry[]> {
    return queries.getTaskHistory(this.queryBackend(), projectId)
  }

  async getMostRecentTask(projectId: string): Promise<TaskHistoryEntry | null> {
    return queries.getMostRecentTask(this.queryBackend(), projectId)
  }

  async getTaskHistoryByType(
    projectId: string,
    classification: TaskHistoryEntry['classification']
  ): Promise<TaskHistoryEntry[]> {
    return queries.getTaskHistoryByType(this.queryBackend(), projectId, classification)
  }

  async getAggregatedFeedback(projectId: string) {
    return queries.getAggregatedFeedback(this.queryBackend(), projectId)
  }

  // =========== Workspace + Tokens (delegated to ./state-storage/workspace) ===========

  private workspaceBackend(): WorkspaceBackend {
    return {
      read: this.read.bind(this),
      update: this.update.bind(this),
      publish: this.publishEvent.bind(this),
      createTaskHistoryEntry: this.createTaskHistoryEntry.bind(this),
      persistHistoryEntry: this.mirrorHistoryEntry.bind(this),
    }
  }

  async startTaskInWorkspace(
    projectId: string,
    task: Omit<WorkspaceTask, 'startedAt'>,
    workspaceId: string
  ): Promise<WorkspaceTask> {
    // Per-workspace gate: a task already active in THIS workspace blocks a new
    // one (same as the singular path), but other workspaces are unaffected.
    const state = await this.read(projectId)
    this.validateTransition(state, 'task', workspaceId)
    const started = await workspace.startTaskInWorkspace(
      this.workspaceBackend(),
      projectId,
      task,
      workspaceId
    )
    // Schema v2 (C4) dual-write: crew/multi-agent workspace cycles previously
    // never appeared in the typed `tasks` table at all — undercounting every
    // parallel-worktree cycle in cost/dashboard/cloud consumers of that table.
    this.mirrorTaskRow(projectId, started, 'in_progress')
    return started
  }

  async getCurrentTaskForWorkspace(
    projectId: string,
    workspaceId: string
  ): Promise<WorkspaceTask | null> {
    return workspace.getCurrentTaskForWorkspace(this.workspaceBackend(), projectId, workspaceId)
  }

  async completeTaskInWorkspace(
    projectId: string,
    workspaceId: string,
    feedback?: TaskFeedback
  ): Promise<WorkspaceTask | null> {
    const completed = await workspace.completeTaskInWorkspace(
      this.workspaceBackend(),
      projectId,
      workspaceId,
      feedback
    )
    if (completed) {
      this.mirrorTaskRow(projectId, completed, 'completed', { completedAt: getTimestamp() })
    }
    return completed
  }

  async getActiveTasks(projectId: string): Promise<WorkspaceTask[]> {
    return workspace.getActiveTasks(this.workspaceBackend(), projectId)
  }

  async getActiveTaskCount(projectId: string): Promise<number> {
    return workspace.getActiveTaskCount(this.workspaceBackend(), projectId)
  }

  async updateWorkspaceTask(
    projectId: string,
    workspaceId: string,
    fields: Partial<WorkspaceTask> & Record<string, unknown>
  ): Promise<WorkspaceTask | null> {
    return workspace.updateWorkspaceTask(this.workspaceBackend(), projectId, workspaceId, fields)
  }

  async addTokens(
    projectId: string,
    tokensIn: number,
    tokensOut: number,
    workspaceId?: string
  ): Promise<{ tokensIn: number; tokensOut: number } | null> {
    return workspace.addTokens(this.workspaceBackend(), projectId, tokensIn, tokensOut, workspaceId)
  }

  // =========== Subtask Methods (delegated to ./state-storage/subtasks) ===========

  private subtaskBackend(): SubtaskBackend {
    return {
      read: this.read.bind(this),
      update: this.update.bind(this),
      publish: this.publishEvent.bind(this),
    }
  }

  async createSubtasks(
    projectId: string,
    items: Omit<Subtask, 'status' | 'startedAt' | 'completedAt' | 'output' | 'summary'>[]
  ): Promise<void> {
    return subtasks.createSubtasks(this.subtaskBackend(), projectId, items)
  }

  async completeSubtask(
    projectId: string,
    completionData: SubtaskCompletionData
  ): Promise<Subtask | null> {
    return subtasks.completeSubtask(this.subtaskBackend(), projectId, completionData)
  }

  async getCurrentSubtask(projectId: string): Promise<Subtask | null> {
    return subtasks.getCurrentSubtask(this.subtaskBackend(), projectId)
  }

  async getNextSubtask(projectId: string): Promise<Subtask | null> {
    return subtasks.getNextSubtask(this.subtaskBackend(), projectId)
  }

  async getPreviousSubtask(projectId: string): Promise<Subtask | null> {
    return subtasks.getPreviousSubtask(this.subtaskBackend(), projectId)
  }

  async getPreviousHandoff(projectId: string) {
    return subtasks.getPreviousHandoff(this.subtaskBackend(), projectId)
  }

  async getSubtasks(projectId: string): Promise<Subtask[]> {
    return subtasks.getSubtasks(this.subtaskBackend(), projectId)
  }

  async getSubtaskProgress(projectId: string) {
    return subtasks.getSubtaskProgress(this.subtaskBackend(), projectId)
  }

  async hasSubtasks(projectId: string): Promise<boolean> {
    return subtasks.hasSubtasks(this.subtaskBackend(), projectId)
  }

  async areAllSubtasksComplete(projectId: string): Promise<boolean> {
    return subtasks.areAllSubtasksComplete(this.subtaskBackend(), projectId)
  }

  async failSubtask(projectId: string, error: string): Promise<Subtask | null> {
    return subtasks.failSubtask(this.subtaskBackend(), projectId, error)
  }

  async skipSubtask(projectId: string, reason: string): Promise<Subtask | null> {
    return subtasks.skipSubtask(this.subtaskBackend(), projectId, reason)
  }

  async blockSubtask(projectId: string, blocker: string): Promise<Subtask | null> {
    return subtasks.blockSubtask(this.subtaskBackend(), projectId, blocker)
  }
}

export const stateStorage = new StateStorage()
